import{_ as a,o as t,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Generating Report Cards","description":"","frontmatter":{},"headers":[],"relativePath":"report-cards/generating.md","filePath":"report-cards/generating.md"}'),s={name:"report-cards/generating.md"};function o(i,e,c,h,p,d){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="generating-report-cards" tabindex="-1">Generating Report Cards <a class="header-anchor" href="#generating-report-cards" aria-label="Permalink to &quot;Generating Report Cards&quot;">​</a></h1><h2 id="step-by-step" tabindex="-1">Step-by-Step <a class="header-anchor" href="#step-by-step" aria-label="Permalink to &quot;Step-by-Step&quot;">​</a></h2><ol><li>Navigate to the player&#39;s profile — tap their name on the Roster screen</li><li>Tap <strong>Generate Report Card</strong> (or Report Cards in the player menu)</li><li>Configure the report: <ul><li><strong>Date range</strong> — choose from presets (This season, Last 30 days, Last 60 days) or set a custom range</li><li><strong>Include mechanics</strong> — toggle on/off; requires at least one mechanics assessment in the date range</li><li><strong>Include training plans</strong> — shows active plans and recently archived plans</li><li><strong>Include coach comments</strong> — enter your comments in the text field</li></ul></li><li>Tap <strong>Generate</strong></li></ol><p>The report card compiles in a few seconds and opens in preview mode.</p><h2 id="what-each-section-shows" tabindex="-1">What Each Section Shows <a class="header-anchor" href="#what-each-section-shows" aria-label="Permalink to &quot;What Each Section Shows&quot;">​</a></h2><p><strong>Season Stats</strong> Key stats for each area the player has data in. Players with no pitching data will not have a pitching section. The app shows only areas where data exists.</p><p><strong>Performance Charts</strong> Trend charts for the player&#39;s key metrics over the selected date range. Charts require a minimum of 5 data points to display.</p><p><strong>Mechanics Assessment</strong> Radar charts for each mechanics area assessed during the date range. The top strength element and top focus area are called out below each radar chart. If no assessments exist in the date range the mechanics section is omitted.</p><p><strong>Training Plans</strong> Active training plans are listed with their focus area and current progress status (Improving, Stable, Declining).</p><p><strong>Coach Comments</strong> Free text — up to 1,000 characters. No formatting requirements. The app does not edit or summarize your comments.</p><h2 id="regenerating-a-report-card" tabindex="-1">Regenerating a Report Card <a class="header-anchor" href="#regenerating-a-report-card" aria-label="Permalink to &quot;Regenerating a Report Card&quot;">​</a></h2><p>Report cards are not stored — they generate fresh each time from current data. To update a report card (for example after adding more games) simply generate it again with the same settings.</p>',12)])])}const m=a(s,[["render",o]]);export{g as __pageData,m as default};
